+#[ignore = "stress integration; run explicitly with --ignored"]
+fn crash_replay_suite_short_integration() {
+    let config = CrashReplaySuiteConfig {
+        schedule_count: 20,
+        min_operations: 100,
+        max_operations: 1000,
+        base_seed: 0xFF5E_ED00_0000_0001,
+        output_dir: None,
+    };
